# Let me map this out properly.
# Original 3x3 block grid positions (br, bc):
# (0,0) A  (0,1) B  (0,2) C
# (1,0) D  (1,1) H  (1,2) E  (H = hole)
# (2,0) F  (2,1) G  (2,2) I

# Output 5x5 block grid. Let me label each output block with the original block it matches.
# First, center 3x3 = original pattern but hole filled.

# Let me systematically extract all 5x5 blocks for Example 0:
out0 = np.array(train_samples[0]['output'])
blocks_orig = {}
inp0 = np.array(train_samples[0]['input'])
non8 = np.argwhere(inp0 != 8)
r1, c1 = non8.min(axis=0)
pattern = inp0[r1:r1+9, c1:c1+9]

for br in range(3):
    for bc in range(3):
        blocks_orig[(br,bc)] = pattern[br*3:(br+1)*3, bc*3:(bc+1)*3]

# Output starts at row r1-3, col c1-3 for the extended 5x5 grid
# Original: r1=3, c1=3. Extended starts at 0,0.
ext_r = r1 - 3
ext_c = c1 - 3

blocks_out = {}
for br in range(5):
    for bc in range(5):
        r = ext_r + br*3
        c = ext_c + bc*3
        if r >= 0 and r+3 <= out0.shape[0] and c >= 0 and c+3 <= out0.shape[1]:
            blocks_out[(br,bc)] = out0[r:r+3, c:c+3]

# Now match each output block to original blocks
for br in range(5):
    for bc in range(5):
        if (br,bc) not in blocks_out:
            continue
        ob = blocks_out[(br,bc)]
        if np.all(ob == 8):
            print(f"Out({br},{bc}) = ALL 8s")
            continue
        matched = False
        for obr in range(3):
            for obc in range(3):
                if np.array_equal(ob, blocks_orig[(obr,obc)]):
                    print(f"Out({br},{bc}) = Orig({obr},{obc})")
                    matched = True
        if not matched:
            print(f"Out({br},{bc}) = {ob.tolist()} (no match)")

