for br in range(3):
    for bc in range(3):
        blocks_orig1[(br,bc)] = pattern1[br*3:(br+1)*3, bc*3:(bc+1)*3]

# The 5x5 block grid center should be at (1,1)-(3,3) of the 5x5 grid
# corresponding to the original 9x9 at rows r1-r1+8, cols c1-c1+8
# The 5x5 extends 3 rows/cols in each direction from the original.
# Top-left of 5x5: (r1-3, c1-3)

ext_r = r1 - 3  # 4-3 = 1
ext_c = c1 - 3  # 3-3 = 0

print(f"Ex1: pattern at ({r1},{c1}), 5x5 starts at ({ext_r},{ext_c})")

for br in range(5):
    for bc in range(5):
        r = ext_r + br*3
        c = ext_c + bc*3
        if r >= 0 and r+3 <= out1.shape[0] and c >= 0 and c+3 <= out1.shape[1]:
            block = out1[r:r+3, c:c+3]
            if np.all(block == 8):
                status = "8s"
            else:
                # Check if it matches expected
                # Expected: for (br,bc) in center (1-3,1-3) → original block
                # For outer ring → reflected block B(2-(br-1), 2-(bc-1)) if in original range
                if 1 <= br <= 3 and 1 <= bc <= 3:
                    exp = blocks_orig1[(br-1, bc-1)]
                    if br-1 == 1 and bc-1 == 1:
                        status = f"center/hole filled: {block.tolist()}"
                    elif np.array_equal(block, exp):
                        status = f"orig({br-1},{bc-1}) ✓"
                    else:
                        status = f"MISMATCH with orig({br-1},{bc-1})"
                else:
                    # Reflected: Out(br,bc) should be B at reflected position
                    # reflected orig pos: (4-2*orig_i, 4-2*orig_j) = (br, bc)
                    # so orig_i = (4-br)/2, orig_j = (4-bc)/2
                    oi = (4-br)//2
                    oj = (4-bc)//2
                    if 0 <= oi <= 2 and 0 <= oj <= 2 and (4-br)%2==0 and (4-bc)%2==0:
                        exp = blocks_orig1[(oi, oj)]
                        if np.array_equal(block, exp):
                            status = f"reflected B({oi},{oj}) ✓"
                        else:
                            status = f"MISMATCH with B({oi},{oj}): got {block.tolist()}"
                    else:
                        status = f"non-integer mapping: {block.tolist()}"
            print(f"  5x5({br},{bc}) at grid({r},{c}): {status}")

